INSERT INTO `question` VALUES ('bulk-multiple-0001','teacher-1','Java 基础','StringBuilder','中','multiple','扩展多选：关于StringBuilder的核心特征，哪些说法正确？','[\"常见应用场景包括循环拼接日志或 SQL 片段\", \"理解 append 有助于掌握 StringBuilder 的核心用法\", \"StringBuilder会自动绕过登录和权限校验，因此不需要鉴权设计\", \"StringBuilder只要被引入就能自动修复所有业务逻辑错误\", \"StringBuilder能够高效拼接可变字符串\"]','[\"StringBuilder能够高效拼接可变字符串\", \"常见应用场景包括循环拼接日志或 SQL 片段\", \"理解 append 有助于掌握 StringBuilder 的核心用法\"]',4,'bulk-choice-20260506'),('bulk-multiple-0002','teacher-1','Java 基础','StringBuilder','中','multiple','扩展多选：在教师端使用StringBuilder时，哪些做法更合理？','[\"在在线考试系统中，StringBuilder可以帮助提升功能的可维护性\", \"StringBuilder只能在管理员端使用，教师端和学生端完全无法复用\", \"StringBuilder不需要任何边界处理，也不需要考虑异常情况\", \"使用 StringBuilder 时应结合边界条件、异常处理和输入校验\", \"StringBuilder的实现应保持职责清晰，避免把无关逻辑混在一起\"]','[\"使用 StringBuilder 时应结合边界条件、异常处理和输入校验\", \"StringBuilder的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，StringBuilder可以帮助提升功能的可维护性\"]',4,'bulk-choice-20260506'),('bulk-multiple-0003','teacher-1','Java 基础','StringBuilder','中','multiple','扩展多选：StringBuilder用于在线考试系统时，哪些关注点是正确的？','[\"把所有用户密码展示在教师端列表中\", \"跳过后端校验，只依赖浏览器页面限制\", \"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\"]','[\"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\"]',4,'bulk-choice-20260506'),('bulk-multiple-0004','teacher-1','Java 基础','StringBuilder','难','multiple','扩展多选：学习StringBuilder时，哪些判断是正确的？','[\"StringBuilder只要被引入就能自动修复所有业务逻辑错误\", \"StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。\", \"StringBuilder适合用于循环拼接日志或 SQL 片段。\", \"关键点可以围绕 append 展开复习\", \"StringBuilder会自动绕过登录和权限校验，因此不需要鉴权设计\"]','[\"StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。\", \"StringBuilder适合用于循环拼接日志或 SQL 片段。\", \"关键点可以围绕 append 展开复习\"]',4,'bulk-choice-20260506'),('bulk-multiple-0005','teacher-1','Java 基础','泛型','中','multiple','扩展多选：关于泛型的核心特征，哪些说法正确？','[\"泛型能够在编译期约束集合或方法的类型\", \"常见应用场景包括公共工具类和集合返回值声明\", \"理解 <T> 有助于掌握 泛型 的核心用法\", \"泛型会自动绕过登录和权限校验，因此不需要鉴权设计\", \"泛型只要被引入就能自动修复所有业务逻辑错误\"]','[\"泛型能够在编译期约束集合或方法的类型\", \"常见应用场景包括公共工具类和集合返回值声明\", \"理解 <T> 有助于掌握 泛型 的核心用法\"]',4,'bulk-choice-20260506'),('bulk-multiple-0006','teacher-1','Java 基础','泛型','中','multiple','扩展多选：在教师端使用泛型时，哪些做法更合理？','[\"泛型的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，泛型可以帮助提升功能的可维护性\", \"泛型只能在管理员端使用，教师端和学生端完全无法复用\", \"泛型不需要任何边界处理，也不需要考虑异常情况\", \"使用 泛型 时应结合边界条件、异常处理和输入校验\"]','[\"使用 泛型 时应结合边界条件、异常处理和输入校验\", \"泛型的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，泛型可以帮助提升功能的可维护性\"]',4,'bulk-choice-20260506'),('bulk-multiple-0007','teacher-1','Java 基础','泛型','中','multiple','扩展多选：泛型用于在线考试系统时，哪些关注点是正确的？','[\"结合角色权限控制，避免越权访问数据\", \"把所有用户密码展示在教师端列表中\", \"跳过后端校验，只依赖浏览器页面限制\", \"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\"]','[\"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\"]',4,'bulk-choice-20260506'),('bulk-multiple-0008','teacher-1','Java 基础','泛型','难','multiple','扩展多选：学习泛型时，哪些判断是正确的？','[\"泛型会自动绕过登录和权限校验，因此不需要鉴权设计\", \"泛型只要被引入就能自动修复所有业务逻辑错误\", \"泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。\", \"泛型适合用于公共工具类和集合返回值声明。\", \"关键点可以围绕 <T> 展开复习\"]','[\"泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。\", \"泛型适合用于公共工具类和集合返回值声明。\", \"关键点可以围绕 <T> 展开复习\"]',4,'bulk-choice-20260506'),('bulk-multiple-0009','teacher-1','Java 基础','异常处理','中','multiple','扩展多选：关于try-catch-finally的核心特征，哪些说法正确？','[\"try-catch-finally只要被引入就能自动修复所有业务逻辑错误\", \"try-catch-finally能够捕获异常并保证必要清理逻辑执行\", \"常见应用场景包括文件读取、网络请求和事务处理\", \"理解 finally 有助于掌握 try-catch-finally 的核心用法\", \"try-catch-finally会自动绕过登录和权限校验，因此不需要鉴权设计\"]','[\"try-catch-finally能够捕获异常并保证必要清理逻辑执行\", \"常见应用场景包括文件读取、网络请求和事务处理\", \"理解 finally 有助于掌握 try-catch-finally 的核心用法\"]',4,'bulk-choice-20260506'),('bulk-multiple-0010','teacher-1','Java 基础','异常处理','中','multiple','扩展多选：在教师端使用try-catch-finally时，哪些做法更合理？','[\"使用 try-catch-finally 时应结合边界条件、异常处理和输入校验\", \"try-catch-finally的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，try-catch-finally可以帮助提升功能的可维护性\", \"try-catch-finally只能在管理员端使用，教师端和学生端完全无法复用\", \"try-catch-finally不需要任何边界处理，也不需要考虑异常情况\"]','[\"使用 try-catch-finally 时应结合边界条件、异常处理和输入校验\", \"try-catch-finally的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，try-catch-finally可以帮助提升功能的可维护性\"]',4,'bulk-choice-20260506'),('bulk-multiple-0011','teacher-1','Java 基础','异常处理','中','multiple','扩展多选：try-catch-finally用于在线考试系统时，哪些关注点是正确的？','[\"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\", \"把所有用户密码展示在教师端列表中\", \"跳过后端校验，只依赖浏览器页面限制\", \"保持接口返回清晰，便于前端给出明确反馈\"]','[\"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\"]',4,'bulk-choice-20260506'),('bulk-multiple-0012','teacher-1','Java 基础','异常处理','难','multiple','扩展多选：学习try-catch-finally时，哪些判断是正确的？','[\"关键点可以围绕 finally 展开复习\", \"try-catch-finally会自动绕过登录和权限校验，因此不需要鉴权设计\", \"try-catch-finally只要被引入就能自动修复所有业务逻辑错误\", \"try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。\", \"try-catch-finally适合用于文件读取、网络请求和事务处理。\"]','[\"try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。\", \"try-catch-finally适合用于文件读取、网络请求和事务处理。\", \"关键点可以围绕 finally 展开复习\"]',4,'bulk-choice-20260506'),('bulk-multiple-0013','teacher-1','Java 基础','枚举','中','multiple','扩展多选：关于enum的核心特征，哪些说法正确？','[\"enum会自动绕过登录和权限校验，因此不需要鉴权设计\", \"enum只要被引入就能自动修复所有业务逻辑错误\", \"enum能够表达固定且有限的业务状态\", \"常见应用场景包括考试状态、题型和用户角色建模\", \"理解 enum 有助于掌握 enum 的核心用法\"]','[\"enum能够表达固定且有限的业务状态\", \"常见应用场景包括考试状态、题型和用户角色建模\", \"理解 enum 有助于掌握 enum 的核心用法\"]',4,'bulk-choice-20260506'),('bulk-multiple-0014','teacher-1','Java 基础','枚举','中','multiple','扩展多选：在教师端使用enum时，哪些做法更合理？','[\"enum不需要任何边界处理，也不需要考虑异常情况\", \"使用 enum 时应结合边界条件、异常处理和输入校验\", \"enum的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，enum可以帮助提升功能的可维护性\", \"enum只能在管理员端使用，教师端和学生端完全无法复用\"]','[\"使用 enum 时应结合边界条件、异常处理和输入校验\", \"enum的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，enum可以帮助提升功能的可维护性\"]',4,'bulk-choice-20260506'),('bulk-multiple-0015','teacher-1','Java 基础','枚举','中','multiple','扩展多选：enum用于在线考试系统时，哪些关注点是正确的？','[\"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\", \"把所有用户密码展示在教师端列表中\", \"跳过后端校验，只依赖浏览器页面限制\"]','[\"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\"]',4,'bulk-choice-20260506'),('bulk-multiple-0016','teacher-1','Java 基础','枚举','难','multiple','扩展多选：学习enum时，哪些判断是正确的？','[\"enum适合用于考试状态、题型和用户角色建模。\", \"关键点可以围绕 enum 展开复习\", \"enum会自动绕过登录和权限校验，因此不需要鉴权设计\", \"enum只要被引入就能自动修复所有业务逻辑错误\", \"enum用于表达固定且有限的业务状态，在考试状态、题型和用户角色建模时可以提升实现的清晰度和稳定性。\"]','[\"enum用于表达固定且有限的业务状态，在考试状态、题型和用户角色建模时可以提升实现的清晰度和稳定性。\", \"enum适合用于考试状态、题型和用户角色建模。\", \"关键点可以围绕 enum 展开复习\"]',4,'bulk-choice-20260506'),('bulk-multiple-0017','teacher-1','Java 基础','注解','中','multiple','扩展多选：关于Annotation的核心特征，哪些说法正确？','[\"理解 @interface 有助于掌握 Annotation 的核心用法\", \"Annotation会自动绕过登录和权限校验，因此不需要鉴权设计\", \"Annotation只要被引入就能自动修复所有业务逻辑错误\", \"Annotation能够为类、方法或字段提供元数据\", \"常见应用场景包括接口校验、依赖注入和路由映射\"]','[\"Annotation能够为类、方法或字段提供元数据\", \"常见应用场景包括接口校验、依赖注入和路由映射\", \"理解 @interface 有助于掌握 Annotation 的核心用法\"]',4,'bulk-choice-20260506'),('bulk-multiple-0018','teacher-1','Java 基础','注解','中','multiple','扩展多选：在教师端使用Annotation时，哪些做法更合理？','[\"Annotation只能在管理员端使用，教师端和学生端完全无法复用\", \"Annotation不需要任何边界处理，也不需要考虑异常情况\", \"使用 Annotation 时应结合边界条件、异常处理和输入校验\", \"Annotation的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，Annotation可以帮助提升功能的可维护性\"]','[\"使用 Annotation 时应结合边界条件、异常处理和输入校验\", \"Annotation的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，Annotation可以帮助提升功能的可维护性\"]',4,'bulk-choice-20260506'),('bulk-multiple-0019','teacher-1','Java 基础','注解','中','multiple','扩展多选：Annotation用于在线考试系统时，哪些关注点是正确的？','[\"跳过后端校验，只依赖浏览器页面限制\", \"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\", \"把所有用户密码展示在教师端列表中\"]','[\"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\"]',4,'bulk-choice-20260506'),('bulk-multiple-0020','teacher-1','Java 基础','注解','难','multiple','扩展多选：学习Annotation时，哪些判断是正确的？','[\"Annotation用于为类、方法或字段提供元数据，在接口校验、依赖注入和路由映射时可以提升实现的清晰度和稳定性。\", \"Annotation适合用于接口校验、依赖注入和路由映射。\", \"关键点可以围绕 @interface 展开复习\", \"Annotation会自动绕过登录和权限校验，因此不需要鉴权设计\", \"Annotation只要被引入就能自动修复所有业务逻辑错误\"]','[\"Annotation用于为类、方法或字段提供元数据，在接口校验、依赖注入和路由映射时可以提升实现的清晰度和稳定性。\", \"Annotation适合用于接口校验、依赖注入和路由映射。\", \"关键点可以围绕 @interface 展开复习\"]',4,'bulk-choice-20260506'),('bulk-multiple-0021','teacher-1','Java 基础','反射','中','multiple','扩展多选：关于Reflection的核心特征，哪些说法正确？','[\"常见应用场景包括框架扫描 Bean 或通用对象映射\", \"理解 Class 有助于掌握 Reflection 的核心用法\", \"Reflection会自动绕过登录和权限校验，因此不需要鉴权设计\", \"Reflection只要被引入就能自动修复所有业务逻辑错误\", \"Reflection能够在运行期读取类结构并动态调用成员\"]','[\"Reflection能够在运行期读取类结构并动态调用成员\", \"常见应用场景包括框架扫描 Bean 或通用对象映射\", \"理解 Class 有助于掌握 Reflection 的核心用法\"]',4,'bulk-choice-20260506'),('bulk-multiple-0022','teacher-1','Java 基础','反射','中','multiple','扩展多选：在教师端使用Reflection时，哪些做法更合理？','[\"在在线考试系统中，Reflection可以帮助提升功能的可维护性\", \"Reflection只能在管理员端使用，教师端和学生端完全无法复用\", \"Reflection不需要任何边界处理，也不需要考虑异常情况\", \"使用 Reflection 时应结合边界条件、异常处理和输入校验\", \"Reflection的实现应保持职责清晰，避免把无关逻辑混在一起\"]','[\"使用 Reflection 时应结合边界条件、异常处理和输入校验\", \"Reflection的实现应保持职责清晰，避免把无关逻辑混在一起\", \"在在线考试系统中，Reflection可以帮助提升功能的可维护性\"]',4,'bulk-choice-20260506'),('bulk-multiple-0023','teacher-1','Java 基础','反射','中','multiple','扩展多选：Reflection用于在线考试系统时，哪些关注点是正确的？','[\"把所有用户密码展示在教师端列表中\", \"跳过后端校验，只依赖浏览器页面限制\", \"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\"]','[\"保持接口返回清晰，便于前端给出明确反馈\", \"保留关键操作日志，便于后续排查和审计\", \"结合角色权限控制，避免越权访问数据\"]',4,'bulk-choice-20260506'),('bulk-multiple-0024','teacher-1','Java 基础','反射','难','multiple','扩展多选：学习Reflection时，哪些判断是正确的？','[\"Reflection只要被引入就能自动修复所有业务逻辑错误\", \"Reflection用于在运行期读取类结构并动态调用成员，在框架扫描 Bean 或通用对象映射时可以提升实现的清晰度和稳定性。\", \"Reflection适合用于框架扫描 Bean 或通用对象映射。\", \"关键点可以围绕 Class 展开复习\", \"Reflection会自动绕过登录和权限校验，因此不需要鉴权设计\"]','[\"Reflection用于在运行期读取类结构并动态调用成员，在框架扫描 Bean 或通用对象映射时可以提升实现的清晰度和稳定性。\", \"Reflection适合用于框架扫描 Bean 或通用对象映射。\", \"关键点可以围绕 Class 展开复习\"]',4,'bulk-choice-20260506'),('bulk-multiple-0025','teacher-1','Java 基础','Lambda','中','multiple','扩展多选：关于Lambda 表达式的核心特征，哪些说法正确？','[\"Lambda 表达式能够用更简洁的函数式写法传递行为\", \"常见应用场景包括集合排序、过滤和回调处理\", \"理解 -> 有助于掌握 Lambda 表达式 的核心用法\", \"Lambda 表达式会自动绕过登录和权限校验，因此不需要鉴权设计\", \"Lambda 表达式只要被引入就能自动修复所有业务逻辑错误\"]','[\"Lambda 表达式能够用更简洁的函数式写法传递行为\", \"常见应用场景包括集合排序、过滤和回调处理\", \"理解 -> 有助于掌握 Lambda 表达式 的核心用法\"]',4,'bulk-choice-20260506'),('bulk-multiple-0026','t