--
-- Table structure for table `submission`
--

DROP TABLE IF EXISTS `submission`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `submission` (
  `id` varchar(64) NOT NULL,
  `exam_id` varchar(64) NOT NULL,
  `student_id` varchar(64) NOT NULL,
  `student_name` varchar(50) NOT NULL,
  `answers_json` json NOT NULL,
  `answer_detail_json` json DEFAULT NULL,
  `switch_count` int NOT NULL DEFAULT '0',
  `suspicious` tinyint(1) NOT NULL DEFAULT '0',
  `suspicious_reasons_json` json DEFAULT NULL,
  `auto_score` int DEFAULT '0',
  `final_score` int DEFAULT '0',
  `status` varchar(20) NOT NULL,
  `started_at` datetime(3) DEFAULT NULL,
  `deadline_at` datetime(3) DEFAULT NULL,
  `submitted_at` datetime(3) DEFAULT NULL,
  `updated_at` datetime(3) DEFAULT NULL,
  `manual_extended_minutes` int DEFAULT '0',
  `graded_by` varchar(50) DEFAULT NULL,
  `question_order_json` json DEFAULT NULL,
  `option_order_json` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_submission_exam_student` (`exam_id`,`student_id`),
  KEY `idx_submission_exam` (`exam_id`),
  KEY `idx_submission_student` (`student_id`),
