--
-- Table structure for table `wrong_book_entry`
--

DROP TABLE IF EXISTS `wrong_book_entry`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wrong_book_entry` (
  `id` varchar(64) NOT NULL,
  `student_id` varchar(64) NOT NULL,
  `student_name` varchar(50) DEFAULT NULL,
  `question_id` varchar(64) NOT NULL,
  `subject` varchar(100) DEFAULT NULL,
  `knowledge_point` varchar(100) DEFAULT NULL,
  `type` varchar(20) DEFAULT NULL,
  `title` text,
  `latest_answer_json` json DEFAULT NULL,
  `expected_answer_json` json DEFAULT NULL,
  `last_retry_answer_json` json DEFAULT NULL,
  `retry_count` int NOT NULL DEFAULT '0',
  `wrong_count` int NOT NULL DEFAULT '0',
  `full_score` int DEFAULT '0',
  `last_score` int DEFAULT '0',
  `last_wrong_at` datetime(3) DEFAULT NULL,
  `last_retry_at` datetime(3) DEFAULT NULL,
  `last_source_submission_id` varchar(64) DEFAULT NULL,
  `last_source_exam_id` varchar(64) DEFAULT NULL,
  `last_retry_correct` tinyint(1) NOT NULL DEFAULT '0',
  `removable` tinyint(1) NOT NULL DEFAULT '0',
  `removed_at` datetime(3) DEFAULT NULL,
  `status` varchar(20) DEFAULT 'active',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_wrong_student_question` (`student_id`,`question_id`),
  KEY `idx_wrong_student` (`student_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

